external_knowledge:
- Reoffense status is determined based on post-release behavior, with 'No' indicating no reoffense and 'Yes' indicating reoffense; 
- Recidivism risk scores are categorized into deciles, with higher scores indicating a greater risk of recidivism;
- Inmates are considered non-reoffenders if they do not reoffend after release, and reoffenders if they do.

sql:
SELECT officer_name
FROM officers
WHERE role = 'Supervisor';

SELECT priors_count
FROM convictions
WHERE most_recent_offense = 'Felony assault';

SELECT reoffense_status, COUNT(*) AS number_of_inmates
FROM post_release_outcomes
GROUP BY reoffense_status;

SELECT score_text, COUNT(*) AS inmate_count
FROM recidivism_scores
GROUP BY score_text;

SELECT COUNT(*) AS reoffenders_count
FROM recidivism_scores
WHERE y = 1;

SELECT COUNT(reoffense_status) AS non_reoffenders
FROM post_release_outcomes
WHERE reoffense_status = 'No';

